#include <vector>
#include <algorithm>

using namespace std;

long long solve(vector<long long> value, vector<long long> limit) {
    int n = value.size();
    vector<pair<long long, long long>> elements;
    for (int i = 0; i < n; ++i) {
        elements.emplace_back(limit[i], value[i]);
    }
    // Sort elements by limit in ascending order, then by value in descending order
    sort(elements.begin(), elements.end(), [](const pair<long long, long long>& a, const pair<long long, long long>& b) {
        if (a.first != b.first) {
            return a.first < b.first;
        } else {
            return a.second > b.second;
        }
    });

    long long res = 0;
    long long active = 0;
    for (int i = 0; i < n; ++i) {
        long long lim = elements[i].first;
        long long val = elements[i].second;
        if (active < lim) {
            res += val;
            active++;
            // Check if current active count triggers any deactivation
            // Since elements are sorted by limit, all previous elements have limit <= current lim
            // So if active >= lim, then we can't activate any more elements with limit <= active
            // But we've already processed elements with smaller limit first
        }
    }
    return res;
}
